        init() { this.themeButtons = document.querySelectorAll('.theme-btn'); this.loadSavedTheme(); this.addEventListeners(); return this; },
        loadSavedTheme() { this.currentTheme = localStorage.getItem(this.THEME_KEY) || 'day'; this.applyTheme(this.currentTheme); },
        applyTheme: Utils.debounce(function(theme) { Utils.raf(() => { document.body.className = `theme-${theme}`; this.updateActiveButton(theme); localStorage.setItem(this.THEME_KEY, theme); }); }, 100),
        updateActiveButton(theme) { this.themeButtons.forEach(btn => { btn.classList.toggle('active', btn.dataset.theme === theme); }); },
        addEventListeners() { this.themeButtons.forEach(button => button.addEventListener('click', () => this.handleThemeClick(button))); },
        handleThemeClick(button) { const theme = button.dataset.theme; if (theme !== this.currentTheme) this.applyTheme(theme); }
    };

    function deepGet(obj, path) {
        if (typeof path !== 'string') return undefined;
        return path.split('.').reduce((prev, curr) => (prev ? prev[curr] : undefined), obj);
    }

    function SafeGetValue(value, defaultValue = "N/A") {
        if (value === undefined || value === null) return defaultValue;
        if (Array.isArray(value)) return value.length > 0 ? String(value[0]) : defaultValue;
        return String(value);
    }

    function updateDisplay() {
        const showDeltaOnly = document.getElementById('data-toggle').checked;
        const toggleLabel = document.getElementById('toggle-label-text');

        localStorage.setItem('showDeltaOnly', String(showDeltaOnly));
        if (showDeltaOnly) {
            toggleLabel.innerText = '仅显示变更';
            toggleLabel.classList.add('active');
        } else {
            toggleLabel.innerText = '显示全部';
            toggleLabel.classList.remove('active');
        }

        const allProperties = document.querySelectorAll('.property');
        allProperties.forEach(p => p.classList.add('hidden'));

        const paths = {
            '世界.日期': 'world-date', '世界.时间': 'world-time', '世界.地点': 'world-location',
            '姜桃.好感度': 'jiangtao-affection', '姜桃.动作体位': 'jiangtao-posture', '姜桃.心理活动': 'jiangtao-psychology',
            '姜桃.服装.上装': 'jiangtao-top', '姜桃.服装.下装': 'jiangtao-bottom', '姜桃.服装.内衣': 'jiangtao-underwear', '姜桃.服装.配饰': 'jiangtao-accessories', '姜桃.服装.鞋': 'jiangtao-shoes',
            '姜桃.身体状态.胸部状态': 'jiangtao-chest', '姜桃.身体状态.阴蒂状态': 'jiangtao-clitoris', '姜桃.身体状态.阴道状态': 'jiangtao-vagina', '姜桃.身体状态.宫颈状态': 'jiangtao-cervix', '姜桃.身体状态.子宫状态': 'jiangtao-uterus', '姜桃.身体状态.肛门状态': 'jiangtao-anus', '姜桃.身体状态.月经状态': 'jiangtao-menstruation',
        };

        for (const path in paths) {
            const deltaValue = deepGet(gameData.delta_data, path);
            const statValue = deepGet(gameData.stat_data, path);

            if (!showDeltaOnly) {
                updateElement(paths[path], statValue);
                if (path === '姜桃.好感度') {
                    updateProgressBar('jiangtao-affection-bar', 'jiangtao-affection', statValue, -100, 200);
                }
            } else {
                if (deltaValue !== undefined) {
                    updateElement(paths[path], deltaValue);
                    if (path === '姜桃.好感度') {
                        updateProgressBar('jiangtao-affection-bar', 'jiangtao-affection', deltaValue, -100, 200);
                    }
                }
            }
        }

        document.querySelectorAll('.section').forEach(section => {
          const visibleProperties = section.querySelectorAll('.property:not(.hidden)');
          section.classList.toggle('hidden', visibleProperties.length === 0);
        });
    }

    function updateElement(elementId, value) {
        if (value === undefined) return;
        const element = document.getElementById(elementId);
        if (element) {
            element.innerText = SafeGetValue(value);
            const propertyDiv = element.closest('.property');
            if (propertyDiv) propertyDiv.classList.remove('hidden');
        }
    }

    function updateProgressBar(barId, valueSpanId, value, min, max) {
        const progressBar = document.getElementById(barId);
        const valueSpan = document.getElementById(valueSpanId);
        if (!valueSpan) return;

        let displayValue = SafeGetValue(value, '0');
        valueSpan.innerText = displayValue;

        let numericValue = 0;
        if (typeof displayValue === 'string' && displayValue.includes('->')) {
            const parts = displayValue.split('->');
            numericValue = parseFloat(parts[parts.length - 1].trim());
        } else {
            numericValue = parseFloat(displayValue);
        }

        if (!progressBar || isNaN(numericValue)) return;

        const range = max - min;
        const boundedValue = Math.max(min, Math.min(numericValue, max));
        let percentage;

        if (range === 0) {
            percentage = boundedValue >= max ? 100 : 0;
        } else {
            percentage = ((boundedValue - min) / range) * 100;
        }

        const zeroPointPercent = ((-min) / range) * 100;

        if (boundedValue >= 0) {
            progressBar.style.backgroundColor = 'var(--progress-bar-positive)';
            progressBar.style.marginLeft = `${zeroPointPercent}%`;
            progressBar.style.width = `${Math.max(0, percentage - zeroPointPercent)}%`;
        } else {
            progressBar.style.backgroundColor = 'var(--progress-bar-negative)';
            progressBar.style.marginLeft = `${percentage}%`;
            progressBar.style.width = `${Math.max(0, zeroPointPercent - percentage)}%`;
        }
    }

    function toggleSection(header) {
        const content = header.nextElementSibling;
        const arrow = header.querySelector('span:last-child');
        const isExpanded = content.classList.toggle('expanded');
        arrow.textContent = isExpanded ? '▼' : '▶';
    }

    async function initDisplayLogic() {
        try {
            document.querySelectorAll('.section-content').forEach(el => el.classList.add('expanded'));
            document.querySelectorAll('.section-header span:last-child').forEach(el => el.textContent = '▼');

            const messages = await getChatMessages(getCurrentMessageId());
            if (!messages || messages.length === 0 || !messages[0].data) {
                document.getElementById('status-card').innerHTML = "<p style='color:red; padding:10px;'>无法加载状态数据。</p>";
                return;
            }

            const data = messages[0].data;
            gameData.stat_data = data.stat_data || {};
            gameData.delta_data = data.delta_data || null;

            const toggleElement = document.getElementById('data-toggle');
           if (gameData.delta_data && Object.keys(gameData.delta_data).length > 0 && Object.keys(gameData.delta_data).some(key => Object.keys(gameData.delta_data[key] || {}).length > 0)) {
                toggleElement.disabled = false;
                const savedState = localStorage.getItem('showDeltaOnly');
                toggleElement.checked = savedState === 'true';
            } else {
                toggleElement.disabled = true;
                toggleElement.checked = false;
            }

            updateDisplay();
        } catch (error) {
            console.error('状态栏加载出错:', error);
            document.getElementById('status-card').innerHTML = `<p style='color:red; padding:10px;'>状态栏加载出错: ${error.message}</p>`;
        }
    }

    document.getElementById('data-toggle').addEventListener('change', updateDisplay);

    document.addEventListener('DOMContentLoaded', function() {
        ThemeManager.init();
        if (typeof getChatMessages === 'function' && typeof getCurrentMessageId === 'function') {
            initDisplayLogic();
